}

message CheckFollowStatusRequest {
    string user_id = 1;
    string target_user_id = 2;
}

message CheckFollowStatusResponse {
    bool is_following = 1;
    int32 status = 2;
}

message Follow {
    string id = 1;
    string user_id = 2;
    string target_user_id = 3;
