### 3. Service 구현 파일

**User Module Service 파일 경로:**
- `/user/src/main/kotlin/com/maum/backend/service/FollowService.kt`

**예상 메서드 시그니처:**
```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
) {
    // 팔로우 추가
    @Transactional
    fun follow(userId: String, targetUserId: String): FollowEntity

    // 팔로우 제거
    @Transactional
    fun unfollow(userId: String, targetUserId: String): Boolean

    // 팔로우 중인 사용자 목록 조회
    @Transactional(readOnly = true)
    fun getFollowings(userId: String, limit: Int, offset: Int): List<FollowEntity>

    // 팔로워 목록 조회
    @Transactional(readOnly = true)
    fun getFollowers(userId: String, limit: Int, offset: Int): List<FollowEntity>

    // 팔로우 상태 확인
    @Transactional(readOnly = true)
    fun checkFollowStatus(userId: String, targetUserId: String): FollowEntity?

    // 팔로우 개수 조회
    @Transactional(readOnly = true)
    fun getFollowingCount(userId: String): Int

    @Transactional(readOnly = true)
    fun getFollowerCount(userId: String): Int
}
```

**UserService (gRPC Service) 파일 경로:**
- `/user/src/main/kotlin/com/maum/backend/controller/UserFollowGrpcService.kt`

**예상 구현:**
```kotlin
@GrpcService
class UserFollowGrpcService(
    private val followService: FollowService,
) : UserFollowServiceGrpc.UserFollowServiceImplBase() {

    override fun follow(
        request: FollowRequest,
        responseObserver: StreamObserver<FollowResponse>,
    ) {
        try {
            val entity = followService.follow(request.userId, request.targetUserId)
            val response = FollowResponse.newBuilder()
                .setFollowId(entity.id)
                .setUserId(entity.userId)
                .setTargetUserId(entity.targetUserId)
                .setStatus(entity.status)
                .setCreatedAt(entity.createdAt.toString())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Follow failed: ${e.message}")
                    .asRuntimeException()
            )
        }
    }

    override fun unfollow(
        request: UnfollowRequest,
        responseObserver: StreamObserver<UnfollowResponse>,
    ) {
        try {
            val success = followService.unfollow(request.userId, request.targetUserId)
            val response = UnfollowResponse.newBuilder()
                .setSuccess(success)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Unfollow failed: ${e.message}")
                    .asRuntimeException()
            )
        }
    }

    override fun getFollowings(
        request: GetFollowingsRequest,
        responseObserver: StreamObserver<GetFollowingsResponse>,
    ) {
        try {
            val entities = followService.getFollowings(
                request.userId, 
                request.limit, 
                request.offset
            )
            val response = GetFollowingsResponse.newBuilder()
                .addAllFollowings(entities.map { it.toProto() })
                .setTotal(followService.getFollowingCount(request.userId))
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Get followings failed: ${e.message}")
                    .asRuntimeException()
            )
        }
    }

    override fun getFollowers(
        request: GetFollowersRequest,
        responseObserver: StreamObserver<GetFollowersResponse>,
    ) {
        try {
            val entities = followService.getFollowers(
                request.userId, 
                request.limit, 
                request.offset
            )
            val response = GetFollowersResponse.newBuilder()
                .addAllFollowers(entities.map { it.toProto() })
                .setTotal(followService.getFollowerCount(request.userId))
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Get followers failed: ${e.message}")
                    .asRuntimeException()
            )
        }
    }

    override fun checkFollowStatus(
        request: CheckFollowStatusRequest,
        responseObserver: StreamObserver<CheckFollowStatusResponse>,
    ) {
        try {
            val entity = followService.checkFollowStatus(
                request.userId, 
                request.targetUserId
            )
            val response = CheckFollowStatusResponse.newBuilder()
                .setIsFollowing(entity != null)
                .setStatus(entity?.status ?: 0)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Check follow status failed: ${e.message}")
                    .asRuntimeException()
            )
        }
    }
}
```

