### 4. GraphQL 스키마 및 Controller

**GraphQL Schema 파일 경로:**
- `/graphql/src/main/resources/graphql/follow.graphqls`

**예상 스키마:**
```graphql
type Follow {
    id: ID!
    userId: String!
    targetUserId: String!
    status: Int!
    createdAt: String!
}

type FollowList {
    follows: [Follow!]!
    total: Int!
}

input FollowInput {
    targetUserId: String!
}

extend type Query {
    followings(limit: Int, offset: Int): FollowList!
    followers(limit: Int, offset: Int): FollowList!
    checkFollowStatus(targetUserId: String!): Boolean!
}

extend type Mutation {
    follow(input: FollowInput!): Follow!
    unfollow(targetUserId: String!): Boolean!
}
```

**GraphQL Controller 파일 경로:**
- `/graphql/src/main/kotlin/com/maum/backend/controller/follow/FollowController.kt`

**예상 구현:**
```kotlin
@Controller
class FollowController(
    private val followService: FollowService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun followings(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): FollowList {
        val response = followService.getFollowings(
            userId, 
            limit ?: 20, 
            offset ?: 0
        )
        return FollowList(
            follows = response.followingsList.map { it.toResponse() },
            total = response.total
        )
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun followers(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): FollowList {
        val response = followService.getFollowers(
            userId, 
            limit ?: 20, 
            offset ?: 0
        )
        return FollowList(
            follows = response.followersList.map { it.toResponse() },
            total = response.total
        )
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun checkFollowStatus(
        @UserId userId: String,
        @Argument targetUserId: String,
    ): Boolean {
        val response = followService.checkFollowStatus(userId, targetUserId)
        return response.isFollowing
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun follow(
        @UserId userId: String,
        @Argument input: FollowInput,
    ): Follow {
        val response = followService.follow(userId, input.targetUserId)
        return response.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun unfollow(
        @UserId userId: String,
        @Argument targetUserId: String,
    ): Boolean {
        return followService.unfollow(userId, targetUserId)
    }
}
```

