### 5. 테스트 파일

**Service 테스트 파일 경로:**
- `/user/src/test/kotlin/com/maum/backend/service/FollowServiceTest.kt`

**예상 테스트 구현:**
```kotlin
@ExtendWith(MockitoExtension::class)
class FollowServiceTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var followService: FollowService

    @Test
    fun `should follow a user successfully`() {
        // given
        val userId = "user-1"
        val targetUserId = "user-2"
        val followEntity = FollowEntity(
            id = "follow-1",
            userId = userId,
            targetUserId = targetUserId,
            status = 0
        )
        `when`(followRepository.save(any())).thenReturn(followEntity)

        // when
        val result = followService.follow(userId, targetUserId)

        // then
        assertThat(result.userId).isEqualTo(userId)
        assertThat(result.targetUserId).isEqualTo(targetUserId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should unfollow a user successfully`() {
        // given
        val userId = "user-1"
        val targetUserId = "user-2"
        val followEntity = FollowEntity(
            id = "follow-1",
            userId = userId,
            targetUserId = targetUserId
        )
        `when`(followRepository.findByUserIdAndTargetUserId(userId, targetUserId))
            .thenReturn(followEntity)
        `when`(followRepository.delete(followEntity)).then { }

        // when
        val result = followService.unfollow(userId, targetUserId)

        // then
        assertThat(result).isTrue()
        verify(followRepository).delete(followEntity)
    }

    @Test
    fun `should return followings list`() {
        // given
        val userId = "user-1"
        val follows = listOf(
            FollowEntity(id = "1", userId = userId, targetUserId = "user-2", status = 0),
            FollowEntity(id = "2", userId = userId, targetUserId = "user-3", status = 0)
        )
        `when`(followRepository.findByUserId(userId)).thenReturn(follows)

        // when
        val result = followService.getFollowings(userId, 20, 0)

        // then
        assertThat(result).hasSize(2)
        verify(followRepository).findByUserId(userId)
    }

    @Test
    fun `should return followers list`() {
        // given
        val userId = "user-1"
        val followers = listOf(
            FollowEntity(id = "1", userId = "user-2", targetUserId = userId, status = 0),
            FollowEntity(id = "2", userId = "user-3", targetUserId = userId, status = 0)
        )
        `when`(followRepository.findByTargetUserId(userId)).thenReturn(followers)

        // when
        val result = followService.getFollowers(userId, 20, 0)

        // then
        assertThat(result).hasSize(2)
        verify(followRepository).findByTargetUserId(userId)
    }

    @Test
    fun `should check follow status`() {
        // given
        val userId = "user-1"
        val targetUserId = "user-2"
        val followEntity = FollowEntity(
            id = "follow-1",
            userId = userId,
            targetUserId = targetUserId
        )
        `when`(followRepository.findByUserIdAndTargetUserId(userId, targetUserId))
            .thenReturn(followEntity)

        // when
        val result = followService.checkFollowStatus(userId, targetUserId)

        // then
        assertThat(result).isNotNull()
        assertThat(result?.userId).isEqualTo(userId)
    }
}
