**예상 구현:**
```kotlin
// 기본 Follow 예외
open class FollowException(
    message: String,
    val code: String = "FOLLOW_ERROR",
) : RuntimeException(message)

// 팔로우 이미 존재
class FollowAlreadyExistsException(
    message: String = "Already following this user",
) : FollowException(message, "FOLLOW_ALREADY_EXISTS")

// 팔로우 관계 없음
class FollowNotFoundException(
    message: String = "Follow relationship not found",
) : FollowException(message, "FOLLOW_NOT_FOUND")

// 자기 자신 팔로우 불가
class CannotFollowSelfException(
    message: String = "Cannot follow yourself",
) : FollowException(message, "CANNOT_FOLLOW_SELF")

// 차단된 사용자
class FollowBlockedException(
    message: String = "This user is blocked",
) : FollowException(message, "FOLLOW_BLOCKED")

// 팔로우 대상 사용자 없음
class TargetUserNotFoundException(
    message: String = "Target user not found",
) : FollowException(message, "TARGET_USER_NOT_FOUND")
